public int caughtSpeeding(int speed, boolean isBirthday) {
    int speedLimitNoTicket = 60;
    int speedLimitSmallTicket = 80;

    if (isBirthday) {
        speedLimitNoTicket += 5;
        speedLimitSmallTicket += 5;
